const tw = $('Resolve Inputs & Defaults').first().json;
const events = [];
const minDuration = tw.minDuration || 0;
const typeFilter = tw.typeFilter || null;

for (const item of items) {
  const e = item.json;
  if (!e.start?.dateTime || !e.end?.dateTime) continue;

  const attendees = e.attendees || [];
  if (attendees.length < 2) continue;

  const startMs = new Date(e.start.dateTime).getTime();
  const endMs = new Date(e.end.dateTime).getTime();
  const durMin = (endMs - startMs) / 60000;
  if (durMin <= 0) continue;
  if (durMin < minDuration) continue;

  const title = (e.summary || '').toLowerCase();
  let type = 'general';
  if (attendees.length === 2) type = '1:1';
  else if (/standup|stand-up|daily.?scrum|daily.?sync/.test(title)) type = 'standup';
  else if (/all.?hands|town.?hall|company.?meeting/.test(title)) type = 'all-hands';
  else if (/retro|retrospective/.test(title)) type = 'retrospective';
  else if (/sprint.?plan|backlog|planning/.test(title)) type = 'planning';
  else if (/review|demo|showcase/.test(title)) type = 'review';
  else if (/interview|screening/.test(title)) type = 'interview';
  else if (/workshop|training|learning/.test(title)) type = 'workshop';
  else if (/brainstorm/.test(title)) type = 'brainstorm';
  else if (/sync|catch.?up|check.?in/.test(title)) type = 'sync';

  if (typeFilter && type !== typeFilter) continue;

  events.push({
    json: {
      meetingId: e.id,
      summary: e.summary || 'Untitled',
      start: e.start.dateTime,
      end: e.end.dateTime,
      durationMinutes: +durMin.toFixed(1),
      attendees: attendees.map(a => ({
        email: a.email,
        name: a.displayName || a.email.split('@')[0],
        status: a.responseStatus || 'unknown',
        isOrganizer: !!a.organizer
      })),
      attendeeCount: attendees.length,
      attendeeEmails: attendees.map(a => a.email).join(', '),
      meetingType: type,
      isRecurring: !!e.recurringEventId,
      meetingLink: e.hangoutLink || e.location || null,
      organizer: e.organizer?.email || null,
      totalWorkingMinutes: tw.totalWorkingMinutes
    }
  });
}

events.sort((a, b) => new Date(a.json.start) - new Date(b.json.start));

for (let i = 0; i < events.length; i++) {
  if (i === 0) { events[i].json.isBackToBack = false; continue; }
  const prevEnd = new Date(events[i-1].json.end).getTime();
  const currStart = new Date(events[i].json.start).getTime();
  events[i].json.isBackToBack = (currStart - prevEnd) < 900000;
}

if (events.length === 0) {
  return [{ json: { _noMeetings: true, weekLabel: tw.weekLabel || tw.rangeLabel } }];
}

return events;

// FIXED v3: Real Fathom response shape:
// { items: [ { title, meeting_title, scheduled_start_time, scheduled_end_time,
//              transcript: [{speaker:{display_name, matched_calendar_invitee_email}, text, timestamp}],
//              default_summary: {markdown_formatted},
//              action_items: [{description, assignee:{name,email}, completed, recording_timestamp}],
//              calendar_invitees: [{name, email, is_external}],
//              recorded_by: {name, email} } ], next_cursor }

const meetings = $('Filter & Classify Events').all();

return items.map((item, i) => {
  const meeting = meetings[i]?.json || {};
  if (meeting._noMeetings) return { json: { _noMeetings: true } };

  const resp = item.json;
  const fathomItems = resp?.items || [];

  // Match Fathom recording to Calendar event by time proximity (within 30 min)
  const calStart = new Date(meeting.start).getTime();
  let bestMatch = null;
  let bestDiff = Infinity;

  for (const fi of fathomItems) {
    const fStart = new Date(fi.scheduled_start_time || fi.recording_start_time || 0).getTime();
    const diff = Math.abs(fStart - calStart);
    if (diff < bestDiff && diff < 1800000) { // within 30 minutes
      bestDiff = diff;
      bestMatch = fi;
    }
  }

  // Extract structured transcript text for AI prompt
  let transcriptText = null;
  let speakerSegments = [];
  let fathomActionItems = [];
  let fathomSummary = null;

  if (bestMatch) {
    // Build readable transcript from speaker-labeled segments
    if (Array.isArray(bestMatch.transcript) && bestMatch.transcript.length > 0) {
      transcriptText = bestMatch.transcript
        .map(seg => `[${seg.timestamp}] ${seg.speaker?.display_name || 'Unknown'}: ${seg.text}`)
        .join('\n');
      // Build per-speaker stats from transcript
      const speakerMap = {};
      for (const seg of bestMatch.transcript) {
        const name = seg.speaker?.display_name || 'Unknown';
        const email = seg.speaker?.matched_calendar_invitee_email || null;
        if (!speakerMap[name]) speakerMap[name] = { name, email, segments: 0, wordCount: 0 };
        speakerMap[name].segments++;
        speakerMap[name].wordCount += (seg.text || '').split(' ').length;
      }
      speakerSegments = Object.values(speakerMap);
    }
    if (bestMatch.default_summary?.markdown_formatted) {
      fathomSummary = bestMatch.default_summary.markdown_formatted;
    }
    if (Array.isArray(bestMatch.action_items)) {
      fathomActionItems = bestMatch.action_items.map(ai => ({
        description: ai.description,
        assignee: ai.assignee?.name || ai.assignee?.email || null,
        completed: ai.completed || false,
        timestamp: ai.recording_timestamp || null
      }));
    }
  }

  return {
    json: {
      ...meeting,
      transcript: transcriptText,
      speakerSegments: speakerSegments,
      fathomSummary: fathomSummary,
      fathomActionItems: fathomActionItems,
      fathomCallId: bestMatch?.url || null,
      hasTranscript: !!transcriptText,
      transcriptSegmentCount: bestMatch?.transcript?.length || 0
    }
  };
});

const results = [];

for (const item of items) {
  const m = item.json;
  if (m._noMeetings) { results.push({ json: m }); continue; }

  let transcriptBlock;
  if (m.hasTranscript && m.transcript) {
    transcriptBlock = 'FULL TRANSCRIPT (' + m.transcriptSegmentCount + ' segments):\n' + m.transcript;
    if (m.fathomSummary) {
      transcriptBlock += '\n\nFATHOM AI SUMMARY:\n' + m.fathomSummary;
    }
    if (m.speakerSegments && m.speakerSegments.length > 0) {
      transcriptBlock += '\n\nSPEAKER WORD COUNTS (for reference):\n' +
        m.speakerSegments.map(s => `  ${s.name}: ${s.wordCount} words across ${s.segments} segments`).join('\n');
    }
    if (m.fathomActionItems && m.fathomActionItems.length > 0) {
      transcriptBlock += '\n\nFATHOM-DETECTED ACTION ITEMS:\n' +
        m.fathomActionItems.map(ai => `  - ${ai.description}` + (ai.assignee ? ` (→ ${ai.assignee})` : '')).join('\n');
    }
  } else {
    transcriptBlock = 'No transcript available. Estimate scores based on the meeting metadata. Use reasonable defaults for a meeting of this type, duration, and attendee count.';
  }

  const schema = [
    '{',
    '  "decisionMinutes": <float>,',
    '  "discussionMinutes": <float>,',
    '  "effectiveMinutes": <float>,',
    '  "idleMinutes": <float>,',
    '  "meetingNecessityScore": <int 0-100>,',
    '  "meetingNecessityReason": "<brief justification>",',
    '  "sentiment": "<positive|neutral|negative|mixed>",',
    '  "keyDecisions": ["<decision>"],',
    '  "actionItems": [{"task":"<what>","owner":"<who or null>","deadline":"<when or null>"}],',
    '  "unresolvedItems": ["<topic not resolved>"],',
    '  "participants": [{',
    '    "name": "<name or email>",',
    '    "email": "<matched email if available>",',
    '    "role": "<facilitator|contributor|observer|dominator>",',
    '    "speakingTimeMinutes": <float>,',
    '    "decisionContributions": <int>,',
    '    "discussionContributions": <int>,',
    '    "contributionScore": <int 0-100>,',
    '    "feedback": "<one sentence constructive feedback>"',
    '  }],',
    '  "improvementSuggestions": ["<actionable suggestion>"],',
    '  "qualitySummary": "<2-3 sentence assessment>"',
    '}'
  ].join('\n');

  const prompt =
    'Analyze this meeting and return a JSON object with EXACTLY this structure (no markdown, no extra text):\n' + schema + '\n\n' +
    'SCORING RULES:\n' +
    '- meetingNecessityScore: 100=must be live discussion, 0=total waste/should be email\n' +
    '- contributionScore: Quality over quantity. Decisive/concise > rambling. Accounts for role.\n' +
    '- effectiveMinutes: Decisions + action planning + focused problem-solving. Must be <= total duration.\n' +
    '- idleMinutes: Small talk, waiting, repetition, tangents. effective + idle ≈ total.\n' +
    '- role: facilitator=ran the meeting, contributor=actively participated, observer=mostly silent, dominator=talked too much relative to value\n' +
    '- Use speaker word counts and Fathom action items (if provided) to inform your estimates.\n\n' +
    'MEETING DATA:\n' +
    'Title: ' + m.summary + '\n' +
    'Type: ' + m.meetingType + '\n' +
    'Duration: ' + m.durationMinutes + ' minutes\n' +
    'Attendees (' + m.attendeeCount + '): ' + m.attendeeEmails + '\n' +
    'Recurring: ' + (m.isRecurring ? 'Yes' : 'No') + '\n' +
    'Back-to-back: ' + (m.isBackToBack ? 'Yes' : 'No') + '\n\n' +
    transcriptBlock;

  results.push({ json: { ...m, _prompt: prompt } });
}

return results;

// FIXED v3: More robust AI response parsing. Handles OpenAI JSON mode quirks.
const merged = $('Match & Extract Fathom Data').all();
const results = [];
let physicalMeetings = [];

for (let i = 0; i < items.length; i++) {
  const aiResp = items[i].json;
  const meeting = merged[i]?.json || {};

  if (meeting._noMeetings) continue;

  // Physical meeting (no Fathom transcript) — count but don't score
  if (!meeting.hasTranscript) {
    physicalMeetings.push({
      summary: meeting.summary || 'Untitled',
      start: meeting.start,
      duration: Math.round(((new Date(meeting.end) - new Date(meeting.start)) / 60000) || 0),
      type: meeting.meetingType || 'general',
      attendees: meeting.attendeeCount || 0
    });
    continue;
  }

  let analysis = {};
  try {
    // jsonOutput=true means content may already be parsed object
    let raw = aiResp;
    if (typeof raw === 'string') {
      raw = raw.replace(/```json|```/g, '').trim();
      analysis = JSON.parse(raw);
    } else if (raw?.content) {
      const c = raw.content;
      analysis = typeof c === 'object' ? c : JSON.parse(String(c).replace(/```json|```/g, '').trim());
    } else if (raw?.message?.content) {
      const c = raw.message.content;
      analysis = typeof c === 'object' ? c : JSON.parse(String(c).replace(/```json|```/g, '').trim());
    } else if (raw?.choices?.[0]?.message?.content) {
      const c = raw.choices[0].message.content;
      analysis = typeof c === 'object' ? c : JSON.parse(String(c).replace(/```json|```/g, '').trim());
    } else if (typeof raw === 'object' && raw.decisionMinutes !== undefined) {
      // Already parsed JSON object
      analysis = raw;
    }
  } catch (e) {
    analysis = { _parseError: e.message };
  }

  const totalMin = meeting.durationMinutes || 0;
  const decMin = parseFloat(analysis.decisionMinutes) || 0;
  const discMin = parseFloat(analysis.discussionMinutes) || 0;
  const effMin = Math.min(parseFloat(analysis.effectiveMinutes) || 0, totalMin);
  const idleMin = parseFloat(analysis.idleMinutes) || 0;
  const necessityScore = analysis.meetingNecessityScore ?? 50;
  const actionItems = analysis.actionItems || [];
  const decisions = analysis.keyDecisions || [];

  // Merge Fathom-detected action items with AI-detected (deduplicate by description)
  const fathomAI = meeting.fathomActionItems || [];
  const allActionItems = [...actionItems];
  for (const fai of fathomAI) {
    const exists = allActionItems.some(ai =>
      (ai.task || '').toLowerCase().includes((fai.description || '').toLowerCase().substring(0, 20))
    );
    if (!exists) allActionItems.push({ task: fai.description, owner: fai.assignee, deadline: null, source: 'fathom' });
  }

  const decDiscRatio = (decMin + discMin) > 0
    ? +((decMin / (decMin + discMin)) * 100).toFixed(1) : 0;

  const effPercent = totalMin > 0
    ? +((effMin / totalMin) * 100).toFixed(1) : 0;

  const actionBonus = Math.min(allActionItems.length * 10, 100);
  const decisionBonus = Math.min(decisions.length * 15, 100);

  const meetingScore = +(
    effPercent * 0.30 +
    decDiscRatio * 0.20 +
    necessityScore * 0.25 +
    actionBonus * 0.15 +
    decisionBonus * 0.10
  ).toFixed(1);

  results.push({
    json: {
      meetingId: meeting.meetingId,
      summary: meeting.summary,
      start: meeting.start,
      end: meeting.end,
      durationMinutes: totalMin,
      meetingType: meeting.meetingType,
      isRecurring: meeting.isRecurring,
      isBackToBack: meeting.isBackToBack,
      attendeeCount: meeting.attendeeCount,
      attendeeEmails: meeting.attendeeEmails,
      hasTranscript: meeting.hasTranscript,
      fathomCallId: meeting.fathomCallId,
      decisionMinutes: decMin,
      discussionMinutes: discMin,
      effectiveMinutes: effMin,
      idleMinutes: idleMin,
      decisionDiscussionRatio: decDiscRatio,
      effectiveTimePercent: effPercent,
      meetingScore: meetingScore,
      meetingNecessityScore: necessityScore,
      meetingNecessityReason: analysis.meetingNecessityReason || '',
      sentiment: analysis.sentiment || 'neutral',
      keyDecisions: decisions,
      actionItems: allActionItems,
      unresolvedItems: analysis.unresolvedItems || [],
      improvementSuggestions: analysis.improvementSuggestions || [],
      qualitySummary: analysis.qualitySummary || '',
      participants: (analysis.participants || []).map(p => ({
        name: p.name,
        email: p.email || null,
        role: p.role || 'contributor',
        speakingTimeMinutes: p.speakingTimeMinutes || 0,
        decisionContributions: p.decisionContributions || 0,
        discussionContributions: p.discussionContributions || 0,
        contributionScore: p.contributionScore || 0,
        feedback: p.feedback || '',
        meetingId: meeting.meetingId,
        meetingDate: meeting.start
      }))
    }
  });
}

// Inject physical/virtual counts into every output item
const virtualCount = results.length;
const physicalCount = physicalMeetings.length;
for (const r of results) {
  r.json.physicalCount = physicalCount;
  r.json.virtualCount = virtualCount;
  r.json.physicalMeetings = physicalMeetings;
}

return results.length > 0 ? results : [{ json: { _empty: true, physicalCount, virtualCount, physicalMeetings } }];

function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  if (typeof val === 'boolean') return val ? 'true' : 'false';
  if (typeof val === 'number') return String(val);
  if (Array.isArray(val) || typeof val === 'object') return "'" + JSON.stringify(val).replace(/'/g, "''") + "'::jsonb";
  return "'" + String(val).replace(/'/g, "''") + "'";
}

const results = [];
for (const item of items) {
  const d = item.json;
  if (d._empty) { results.push({ json: { _sql: 'SELECT 1', ...d } }); continue; }
  const sql = `INSERT INTO meeting_metrics (meeting_id, summary, start_time, end_time, duration_minutes, meeting_type, is_recurring, is_back_to_back, attendee_count, has_transcript, fathom_call_id, decision_minutes, discussion_minutes, effective_minutes, idle_minutes, decision_discussion_ratio, effective_time_percent, meeting_score, meeting_necessity_score, meeting_necessity_reason, sentiment, key_decisions, action_items, unresolved_items, improvement_suggestions, quality_summary) VALUES (${esc(d.meetingId)}, ${esc(d.summary)}, ${esc(d.start)}, ${esc(d.end)}, ${esc(d.durationMinutes)}, ${esc(d.meetingType)}, ${esc(d.isRecurring)}, ${esc(d.isBackToBack)}, ${esc(d.attendeeCount)}, ${esc(d.hasTranscript)}, ${esc(d.fathomCallId)}, ${esc(d.decisionMinutes)}, ${esc(d.discussionMinutes)}, ${esc(d.effectiveMinutes)}, ${esc(d.idleMinutes)}, ${esc(d.decisionDiscussionRatio)}, ${esc(d.effectiveTimePercent)}, ${esc(d.meetingScore)}, ${esc(d.meetingNecessityScore)}, ${esc(d.meetingNecessityReason)}, ${esc(d.sentiment)}, ${esc(d.keyDecisions)}, ${esc(d.actionItems)}, ${esc(d.unresolvedItems)}, ${esc(d.improvementSuggestions)}, ${esc(d.qualitySummary)}) ON CONFLICT (meeting_id) DO UPDATE SET created_at = NOW()`;
  results.push({ json: { _sql: sql, ...d } });
}
return results;

function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  if (typeof val === 'boolean') return val ? 'true' : 'false';
  if (typeof val === 'number') return String(val);
  return "'" + String(val).replace(/'/g, "''") + "'";
}

const metrics = $('Compute Scores & Metrics').all();
const results = [];

for (const m of metrics) {
  if (m.json._empty) continue;
  for (const p of (m.json.participants || [])) {
    const data = {
      meeting_id: p.meetingId,
      meeting_date: p.meetingDate,
      participant_name: p.name,
      participant_email: p.email,
      role: p.role,
      speaking_time_minutes: p.speakingTimeMinutes,
      decision_contributions: p.decisionContributions,
      discussion_contributions: p.discussionContributions,
      contribution_score: p.contributionScore,
      feedback: p.feedback
    };
    const sql = `INSERT INTO participant_metrics (meeting_id, meeting_date, participant_name, participant_email, role, speaking_time_minutes, decision_contributions, discussion_contributions, contribution_score, feedback) VALUES (${esc(data.meeting_id)}, ${esc(data.meeting_date)}, ${esc(data.participant_name)}, ${esc(data.participant_email)}, ${esc(data.role)}, ${esc(data.speaking_time_minutes)}, ${esc(data.decision_contributions)}, ${esc(data.discussion_contributions)}, ${esc(data.contribution_score)}, ${esc(data.feedback)}) ON CONFLICT (meeting_id, participant_name) DO UPDATE SET created_at = NOW()`;
    results.push({ json: { ...data, _sql: sql } });
  }
}

return results.length > 0 ? results : [{ json: { _skip: true, _sql: 'SELECT 1' } }];

const meetings = $('Query Weekly Summary').all().map(i => i.json);
const prevRaw = $('Query Previous Week').first()?.json || {};
const participants = $('Query Participant Leaderboard').all().map(i => i.json);
let tw = {};
try { tw = $('Resolve Inputs & Defaults').first().json; } catch(e) { tw = { weekLabel: 'Latest Week', totalWorkingMinutes: 2400 }; }
let rawEvents = [];
try { rawEvents = $('Filter & Classify Events').all().map(i => i.json).filter(e => !e._noMeetings); } catch(e) { rawEvents = []; }

const count = meetings.length;
let physicalCount = 0;
let virtualCount = count;
try {
  const csFirst = $('Compute Scores & Metrics').first()?.json || {};
  physicalCount = csFirst.physicalCount || 0;
  virtualCount = csFirst.virtualCount || count;
} catch(e) {}
const totalMeetingsAll = count + physicalCount;
const totalMin = meetings.reduce((s, m) => s + (parseFloat(m.duration_minutes) || 0), 0);
const totalHrs = (totalMin / 60).toFixed(1);
const avgScore = count > 0 ? (meetings.reduce((s, m) => s + (parseFloat(m.meeting_score) || 0), 0) / count).toFixed(1) : '0';
const avgEff = count > 0 ? (meetings.reduce((s, m) => s + (parseFloat(m.effective_time_percent) || 0), 0) / count).toFixed(1) : '0';
const avgDDR = count > 0 ? (meetings.reduce((s, m) => s + (parseFloat(m.decision_discussion_ratio) || 0), 0) / count).toFixed(1) : '0';
const avgNecessity = count > 0 ? (meetings.reduce((s, m) => s + (parseFloat(m.meeting_necessity_score) || 0), 0) / count).toFixed(1) : '0';
const density = ((totalMin / (tw.totalWorkingMinutes || 2400)) * 100).toFixed(1);
const b2bCount = rawEvents.filter(m => m.isBackToBack).length;
const recurringCount = meetings.filter(m => m.is_recurring).length;
const transcriptRate = count > 0 ? ((meetings.filter(m => m.has_transcript).length / count) * 100).toFixed(0) : '0';
const withFathom = meetings.filter(m => m.fathom_call_id).length;

const prevCount = parseInt(prevRaw.prev_count) || 0;
const prevAvgScore = parseFloat(prevRaw.prev_avg_score) || 0;
const prevAvgEff = parseFloat(prevRaw.prev_avg_effective) || 0;
const prevTotalMin = parseFloat(prevRaw.prev_total_minutes) || 0;

const trend = (curr, prev, dec) => {
  if (prev === 0) return '';
  const d = curr - prev;
  if (Math.abs(d) < 0.5) return ' <span style="color:#888">(steady)</span>';
  const color = d > 0 ? '#00C48C' : '#FF3B5C';
  const arrow = d > 0 ? '↑' : '↓';
  return ' <span style="color:' + color + ';font-weight:600">' + arrow + Math.abs(d).toFixed(dec || 1) + '</span>';
};

const badge = (val, max, thresholds) => {
  const v = parseFloat(val) || 0;
  let color = '#FF3B5C';
  if (v >= thresholds[1]) color = '#00C48C';
  else if (v >= thresholds[0]) color = '#FFB800';
  return '<span style="background:' + color + ';color:#fff;padding:2px 8px;border-radius:10px;font-size:13px;font-weight:600">' + v.toFixed(1) + (max ? '/' + max : '%') + '</span>';
};

const sorted = [...meetings].sort((a, b) => (parseFloat(b.meeting_score) || 0) - (parseFloat(a.meeting_score) || 0));
const top3 = sorted.slice(0, 3);
const bottom3 = count > 3 ? sorted.slice(-3).reverse() : [];
const couldBeEmail = meetings.filter(m => (parseFloat(m.meeting_necessity_score) || 100) < 40);

const byType = {};
for (const m of meetings) {
  const t = m.meeting_type || 'general';
  if (!byType[t]) byType[t] = { count: 0, totalScore: 0, totalMin: 0 };
  byType[t].count++;
  byType[t].totalScore += parseFloat(m.meeting_score) || 0;
  byType[t].totalMin += parseFloat(m.duration_minutes) || 0;
}

let h = '<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="margin:0;padding:0;background:#f4f6f9;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,Helvetica,Arial,sans-serif">';
h += '<div style="max-width:680px;margin:20px auto;background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 2px 12px rgba(0,0,0,0.08)">';
h += '<div style="background:linear-gradient(135deg,#1E1E2E 50%,#FF6600);padding:28px 32px;color:#fff">';
h += '<h1 style="margin:0 0 4px 0;font-size:22px">📊 Weekly Meeting Efficiency Report</h1>';
h += '<p style="margin:0;opacity:0.85;font-size:14px">📅 ' + tw.weekLabel + ' · ' + count + ' virtual (analyzed) + ' + physicalCount + ' physical meetings</p>';
h += '</div>';

h += '<div style="display:flex;flex-wrap:wrap;gap:0;border-bottom:1px solid #eee">';
const statBox = (icon, label, value, sub) => '<div style="flex:1;min-width:140px;padding:18px 20px;text-align:center;border-right:1px solid #eee"><div style="font-size:22px">' + icon + '</div><div style="font-size:22px;font-weight:700;color:#1a1a2e">' + value + '</div><div style="font-size:12px;color:#888;margin-top:2px">' + label + '</div>' + (sub ? '<div style="font-size:11px;color:#aaa;margin-top:2px">' + sub + '</div>' : '') + '</div>';
h += statBox('📅', 'Meetings', count, trend(count, prevCount, 0));
h += statBox('⏱', 'Hours', totalHrs + 'h', density + '% density' + trend(totalMin/60, prevTotalMin/60, 1));
h += statBox('🎯', 'Avg Score', avgScore + '/100', trend(parseFloat(avgScore), prevAvgScore, 1));
h += statBox('⚡', 'Effective', avgEff + '%', trend(parseFloat(avgEff), prevAvgEff, 1));
h += '</div>';

h += '<div style="display:flex;gap:0;border-bottom:1px solid #eee">';
h += '<div style="flex:1;padding:12px 20px;text-align:center;border-right:1px solid #eee"><span style="font-size:16px;font-weight:700;color:#00C48C">' + count + '</span> <span style="font-size:12px;color:#888">Virtual (Analyzed)</span></div>';
h += '<div style="flex:1;padding:12px 20px;text-align:center;border-right:1px solid #eee"><span style="font-size:16px;font-weight:700;color:#FF6600">' + physicalCount + '</span> <span style="font-size:12px;color:#888">Physical (In-person)</span></div>';
