// Resolve user form inputs with smart defaults
// Triggered from: Form Trigger, Weekly Schedule, or Manual Trigger
const now = new Date();

// Determine source — form trigger passes $json with field names
const inp = $input.first()?.json || {};

// Check if this came from a form (form fields present)
const hasFormInput = !!(inp['Date From'] || inp['Date To'] || inp['Work Hours Per Day']);

// --- Date range ---
let from, to;

if (inp['Date From']) {
  from = new Date(inp['Date From']);
  from.setHours(0,0,0,0);
} else {
  // Default: last full Monday
  const day = now.getDay();
  const diff = day === 0 ? -6 : 1 - day;
  from = new Date(now);
  from.setDate(now.getDate() + diff - 7);
  from.setHours(0,0,0,0);
}

if (inp['Date To']) {
  to = new Date(inp['Date To']);
  to.setHours(23,59,59,999);
} else {
  // Default: last Sunday (6 days after last Monday)
  to = new Date(from);
  to.setDate(from.getDate() + 6);
  to.setHours(23,59,59,999);
}

// Previous period (same duration, shifted back)
const rangeDays = Math.round((to - from) / 86400000) + 1;
const prevFrom = new Date(from); prevFrom.setDate(prevFrom.getDate() - rangeDays);
const prevTo   = new Date(to);   prevTo.setDate(prevTo.getDate() - rangeDays);

// --- Work hours ---
const WORK_HRS  = parseFloat(inp['Work Hours Per Day'])  || 8;
const WORK_DAYS = parseFloat(inp['Work Days Per Week'])  || 5;
const MIN_DURATION = parseFloat(inp['Minimum Meeting Duration (minutes)']) || 0;
const typeFilter = (inp['Filter Meeting Type'] || 'All (default)') === 'All (default)'
  ? null : inp['Filter Meeting Type'];

const weekLabel = from.toLocaleDateString('en-US', {month:'short',day:'numeric'})
  + ' – ' + to.toLocaleDateString('en-US', {month:'short',day:'numeric',year:'numeric'});

return [{
  json: {
    from: from.toISOString(),
    to:   to.toISOString(),
    prevFrom: prevFrom.toISOString(),
    prevTo:   prevTo.toISOString(),
    weekLabel,
    totalWorkingMinutes: WORK_HRS * WORK_DAYS * 60,
    workHoursPerDay:  WORK_HRS,
    workDays:         WORK_DAYS,
    minDuration:      MIN_DURATION,
    typeFilter:       typeFilter,
    userCustomized:   hasFormInput,
    rangeLabel: hasFormInput
      ? 'Custom range: ' + weekLabel
      : 'Auto: last full week (' + weekLabel + ')'
  }
}];

