// Donut chart values
const totalDecMin = meetings.reduce((s,m)=>s+(parseFloat(m.decision_minutes)||0),0);
const totalDiscMin = meetings.reduce((s,m)=>s+(parseFloat(m.discussion_minutes)||0),0);
const totalIdleMin = meetings.reduce((s,m)=>s+(parseFloat(m.idle_minutes)||0),0);
const totalAllMin = totalDecMin+totalDiscMin+totalIdleMin||1;
const decPct = Math.round(totalDecMin/totalAllMin*100);
const discPct = Math.round(totalDiscMin/totalAllMin*100);
const idlePct = 100-decPct-discPct;

// SVG donut segments
const r=52, cx=70, cy=70, circ=2*Math.PI*r;
function segment(pct,offset,color){
  const dash=pct/100*circ;
  return `<circle cx="${cx}" cy="${cy}" r="${r}" fill="none" stroke="${color}" stroke-width="22" stroke-dasharray="${dash.toFixed(1)} ${(circ-dash).toFixed(1)}" stroke-dashoffset="${(-offset/100*circ).toFixed(1)}" transform="rotate(-90 ${cx} ${cy})"/>`;
}
const donutSvg = `<svg width="150" height="150" viewBox="0 0 140 140">
  <circle cx="70" cy="70" r="52" fill="none" stroke="#F5F6FA" stroke-width="22"/>
  ${segment(decPct,0,'#FF6600')}
  ${segment(discPct,decPct,'#00C48C')}
  ${segment(idlePct,decPct+discPct,'#FFB800')}
</svg>`;

