const meetingDetailCards = sorted.map((m, i) => {
  const startDate = new Date(m.start_time);
  const dateStr = startDate.toLocaleDateString('en-US',{weekday:'short',month:'short',day:'numeric'});
  const timeStr = startDate.toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit'});
  const sc = parseFloat(m.meeting_score)||0;
  const eff = parseFloat(m.effective_time_percent)||0;
  const ddr = parseFloat(m.decision_discussion_ratio)||0;
  const necessity = parseFloat(m.meeting_necessity_score)||0;
  let decisions=[]; try{decisions=typeof m.key_decisions==='string'?JSON.parse(m.key_decisions):m.key_decisions||[];}catch(e){}
  let actions=[]; try{actions=typeof m.action_items==='string'?JSON.parse(m.action_items):m.action_items||[];}catch(e){}
  let unresolved=[]; try{unresolved=typeof m.unresolved_items==='string'?JSON.parse(m.unresolved_items):m.unresolved_items||[];}catch(e){}
  const barColor=sc>=70?'#00C48C':sc>=45?'#FFB800':'#FF3B5C';
  const fathomLink=m.fathom_call_id?`<a href="${m.fathom_call_id}" target="_blank" style="color:#FF6600;font-size:12px;text-decoration:none;font-weight:600">\uD83C\uDF99 Recording</a>`:'';
  const txBadge=m.has_transcript?'<span style="background:#E8FAF4;color:#00C48C;padding:2px 8px;border-radius:4px;font-size:10px;font-weight:700">TRANSCRIBED</span>':'<span style="background:#F5F6FA;color:#9898B8;padding:2px 8px;border-radius:4px;font-size:10px;font-weight:700">NO TRANSCRIPT</span>';
  const decisionsHtml=decisions.length>0?decisions.map(dd=>`<li>${typeof dd==='string'?dd:dd.task||dd.decision||JSON.stringify(dd)}</li>`).join(''):'<li style="color:#9898B8">None recorded</li>';
  const actionsHtml=actions.length>0?actions.map(a=>{
    if(typeof a==='string') return `<li>${a}</li>`;
    return `<li><strong>${a.task||a.action||''}</strong>${a.owner?' \u2014 '+a.owner:''}${a.deadline?' (by '+a.deadline+')':''}</li>`;
  }).join(''):'<li style="color:#9898B8">None assigned</li>';
  const unresolvedHtml=unresolved.length>0?unresolved.map(u=>`<li style="color:#FF3B5C">${u}</li>`).join(''):'<li style="color:#00C48C">All resolved \u2713</li>';
  return `<div class="mtg-card" style="animation-delay:${i*0.05}s">
    <div class="mtg-header" onclick="this.parentElement.classList.toggle('expanded')">
      <div style="display:flex;align-items:center;gap:12px;flex:1;min-width:0">
        <div style="font-size:18px">${typeEmoji(m.meeting_type)}</div>
        <div style="min-width:0">
          <div style="font-weight:700;font-size:14px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${m.summary||'Untitled Meeting'}</div>
          <div style="font-size:11.5px;color:#9898B8;margin-top:2px">${dateStr} ${timeStr} \u00b7 ${m.meeting_type||'general'} \u00b7 ${m.duration_minutes}min \u00b7 ${m.attendee_count} ppl</div>
        </div>
      </div>
      <div style="display:flex;align-items:center;gap:14px;flex-shrink:0">
        ${txBadge}
        ${scoreBadge(sc)}
        <div style="width:60px;height:6px;background:#f0f0f5;border-radius:3px"><div style="width:${sc}%;height:100%;background:${barColor};border-radius:3px"></div></div>
        <div class="mtg-chevron">\u25be</div>
      </div>
    </div>
    <div class="mtg-body">
      <div class="mtg-metrics">
        <div class="mtg-metric"><div class="mtg-metric-val" style="color:#00C48C">${eff}%</div><div class="mtg-metric-lbl">Effective</div></div>
        <div class="mtg-metric"><div class="mtg-metric-val" style="color:#FF6600">${ddr}%</div><div class="mtg-metric-lbl">Decision Ratio</div></div>
        <div class="mtg-metric"><div class="mtg-metric-val" style="color:#3B82F6">${necessity}/100</div><div class="mtg-metric-lbl">Necessity</div></div>
        <div class="mtg-metric"><div class="mtg-metric-val" style="color:#9898B8">${m.sentiment||'neutral'}</div><div class="mtg-metric-lbl">Sentiment</div></div>
        <div class="mtg-metric"><div class="mtg-metric-val" style="color:#FFB800">${m.is_recurring?'\uD83D\uDD01 Yes':'No'}</div><div class="mtg-metric-lbl">Recurring</div></div>
        <div class="mtg-metric"><div class="mtg-metric-val" style="color:${m.is_back_to_back?'#FF3B5C':'#00C48C'}">${m.is_back_to_back?'\u26a0\ufe0f Yes':'No'}</div><div class="mtg-metric-lbl">Back-to-back</div></div>
      </div>
      ${m.quality_summary?'<div class="mtg-summary">'+m.quality_summary+'</div>':''}
      <div class="mtg-details-grid">
        <div><div class="mtg-section-title">\u2705 Key Decisions</div><ul class="mtg-list mtg-list-green">${decisionsHtml}</ul></div>
        <div><div class="mtg-section-title">\uD83D\uDCCB Action Items</div><ul class="mtg-list mtg-list-orange">${actionsHtml}</ul></div>
        <div><div class="mtg-section-title">\uD83D\uDEA8 Unresolved</div><ul class="mtg-list mtg-list-red">${unresolvedHtml}</ul></div>
      </div>
      ${fathomLink?'<div style="margin-top:14px">'+fathomLink+'</div>':''}
      ${m.meeting_necessity_reason?'<div style="margin-top:10px;font-size:12.5px;color:#4A4A6A;background:#F9FAFB;padding:10px 14px;border-radius:8px;border-left:3px solid #FFB800"><strong style="color:#7A5500">Necessity note:</strong> '+m.meeting_necessity_reason+'</div>':''}
    </div>
  </div>`;
}).join('');

const html = `<!DOCTYPE html>
<html lang="en">
<head>
