.run-status{background:#FFF9E6;border:1px solid rgba(255,184,0,.3);border-left:4px solid #FFB800;border-radius:10px;padding:12px 16px;font-size:13px;color:#7A5500;margin-bottom:20px;display:none}
@media(max-width:900px){.sidebar{display:none}.main{margin-left:0}.kpi-grid{grid-template-columns:repeat(2,1fr)}.grid2,.grid3{grid-template-columns:1fr}.form-grid{grid-template-columns:1fr 1fr}}
@keyframes fadeUp{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:translateY(0)}}
.mtg-card{background:#fff;border:1px solid #E8EAEE;border-radius:11px;margin-bottom:10px;overflow:hidden;transition:all .2s;animation:fadeUp .4s ease both}.mtg-card:hover{border-color:#FF6600;box-shadow:0 2px 12px rgba(255,102,0,.08)}.mtg-header{display:flex;align-items:center;justify-content:space-between;padding:14px 18px;cursor:pointer;gap:12px}.mtg-chevron{font-size:14px;color:#9898B8;transition:transform .2s}.mtg-card.expanded .mtg-chevron{transform:rotate(180deg)}.mtg-body{display:none;padding:0 18px 18px;border-top:1px solid #E8EAEE}.mtg-card.expanded .mtg-body{display:block}.mtg-metrics{display:grid;grid-template-columns:repeat(6,1fr);gap:12px;padding:16px 0;border-bottom:1px solid #F0F0F5;margin-bottom:16px}.mtg-metric{text-align:center}.mtg-metric-val{font-size:16px;font-weight:800;font-family:"JetBrains Mono",monospace}.mtg-metric-lbl{font-size:10px;color:var(--muted);text-transform:uppercase;letter-spacing:.5px;margin-top:3px;font-weight:600}.mtg-summary{font-size:13px;color:#4A4A6A;line-height:1.6;padding:12px 16px;background:#F9FAFB;border-radius:8px;margin-bottom:16px;border-left:3px solid #FF6600}.mtg-details-grid{display:grid;grid-template-columns:1fr 1fr 1fr;gap:16px}.mtg-section-title{font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:#1A1A2E;margin-bottom:8px}.mtg-list{list-style:none;padding:0;font-size:13px;color:#4A4A6A}.mtg-list li{padding:5px 0;padding-left:14px;position:relative}.mtg-list li::before{content:"";position:absolute;left:0;top:11px;width:6px;height:6px;border-radius:50%}.mtg-list-green li::before{background:#00C48C}.mtg-list-orange li::before{background:#FF6600}.mtg-list-red li::before{background:#FF3B5C}.expand-all-btn{background:none;border:1px solid #E8EAEE;color:#9898B8;padding:5px 12px;border-radius:6px;font-size:11px;font-weight:600;cursor:pointer;font-family:"Figtree",sans-serif;transition:all .15s}.expand-all-btn:hover{border-color:#FF6600;color:#FF6600}@media(max-width:900px){.mtg-metrics{grid-template-columns:repeat(3,1fr)}.mtg-details-grid{grid-template-columns:1fr}}
.kpi-card,.card{animation:fadeUp .5s ease both}
