<body>
<aside class="sidebar">
  <div class="logo">
    <div class="logo-mark">O</div>
    <div><div class="logo-brand">OrangeHRM</div><div class="logo-sub">Meeting Analytics</div></div>
  </div>
  <div class="nav-label">Analytics</div>
  <a class="nav-item active" href="#">📊 Meeting Efficiency <span class="nav-badge">Live</span></a>
  <a class="nav-item" href="#">👥 Team Insights</a>
  <a class="nav-item" href="#">📈 Trends</a>
  <div class="nav-label">Management</div>
  <a class="nav-item" href="#">🎯 Action Items <span class="nav-badge">${allUnresolved.length}</span></a>
  <a class="nav-item" href="#">📅 Calendar</a>
  <a class="nav-item" href="#">⚙️ Settings</a>
  <div class="sidebar-footer">
    <div class="avatar">HR</div>
    <div><div style="font-size:12px;font-weight:600;color:#fff">OrangeHRM Admin</div><div style="font-size:10.5px;color:rgba(255,255,255,.4)">HR Admin</div></div>
  </div>
</aside>

<main class="main">
  <div class="topbar">
    <div>
      <h1>Meeting Efficiency Dashboard</h1>
      <p>AI-powered · n8n · GPT-4.1 · Fathom AI · Live from PostgreSQL</p>
    </div>
    <div style="display:flex;align-items:center;gap:10px">
      <div class="week-pill" id="weekPill">📅 ${rangeLabel}</div>
      <button class="btn" onclick="refreshDashboard()" id="refreshBtn">🔄 Refresh</button>
    </div>
  </div>

  <div class="content">

    <!-- Analysis form -->
    <div class="form-panel" id="formPanel">
      <div class="form-panel-title">⚙️ Run Custom Analysis</div>
      <div class="form-grid">
        <div class="form-field"><label>Date From</label><input type="date" id="dateFrom" placeholder="Default: last Monday"></div>
        <div class="form-field"><label>Date To</label><input type="date" id="dateTo" placeholder="Default: last Sunday"></div>
        <div class="form-field"><label>Work Hours / Day</label><input type="number" id="workHours" min="1" max="24" placeholder="Default: 8"></div>
        <div class="form-field"><label>Work Days / Week</label><input type="number" id="workDays" min="1" max="7" placeholder="Default: 5"></div>
        <div class="form-field"><label>Min Duration (min)</label><input type="number" id="minDuration" min="0" placeholder="0 = all meetings"></div>
        <div class="form-field"><label>Filter Meeting Type</label>
          <select id="typeFilter">
            <option value="">All types</option>
            <option>standup</option><option>1:1</option><option>planning</option>
            <option>review</option><option>retrospective</option><option>all-hands</option><option>sync</option>
          </select>
        </div>
      </div>
      <div class="form-actions">
        <button class="btn" onclick="runAnalysis()" id="runBtn">▶ Run Analysis</button>
        <button class="btn-skip" onclick="skipForm()">Skip — use defaults</button>
        <span class="status-msg" id="statusMsg"></span>
      </div>
    </div>

    <div class="run-status" id="runStatus">⏳ Analysis is running in the background. This page will auto-refresh in 90 seconds when results are ready.</div>

    <!-- KPI Cards -->
    <div class="kpi-grid">
      <div class="kpi-card" style="--glow:rgba(0,196,140,.12)">
        <div class="kpi-icon" style="background:#E8FAF4">💻</div>
        <div class="kpi-val" style="color:#00C48C">${count}</div>
        <div class="kpi-lbl">Virtual Meetings</div>
        <div class="kpi-trend" style="color:#9898B8">analyzed with AI</div>
      </div>
      <div class="kpi-card" style="--glow:rgba(255,102,0,.12)">
        <div class="kpi-icon" style="background:#FFF0E6">🏢</div>
        <div class="kpi-val" style="color:#FF6600">${physicalCount}</div>
        <div class="kpi-lbl">Physical Meetings</div>
        <div class="kpi-trend" style="color:#9898B8">in-person (no transcript)</div>
      </div>
      <div class="kpi-card" style="--glow:rgba(0,196,140,.12)">
        <div class="kpi-icon" style="background:#E8FAF4">⏱</div>
        <div class="kpi-val" style="color:#00C48C">${(totalMin/60).toFixed(1)}h</div>
        <div class="kpi-lbl">Hours Spent</div>
        <div class="kpi-trend" style="color:#9898B8">${totalMin.toFixed(0)} total minutes</div>
      </div>
      <div class="kpi-card" style="--glow:rgba(59,130,246,.12)">
        <div class="kpi-icon" style="background:#EEF4FF">🎯</div>
        <div class="kpi-val" style="color:#3B82F6">${avgScore}</div>
        <div class="kpi-lbl">Avg Score /100</div>
        <div class="kpi-trend" style="color:${parseFloat(avgScore)>=70?'#00C48C':parseFloat(avgScore)>=45?'#FFB800':'#FF3B5C'}">${parseFloat(avgScore)>=70?'✅ Healthy':parseFloat(avgScore)>=45?'⚠️ Moderate':'🔴 Needs work'}</div>
      </div>
      <div class="kpi-card" style="--glow:rgba(255,184,0,.12)">
        <div class="kpi-icon" style="background:#FFF9E6">⚡</div>
        <div class="kpi-val" style="color:#FFB800">${avgEff}%</div>
        <div class="kpi-lbl">Effective Time</div>
        <div class="kpi-trend" style="color:#9898B8">avg across meetings</div>
      </div>
      <div class="kpi-card" style="--glow:rgba(255,59,92,.12)">
        <div class="kpi-icon" style="background:#FFF0F3">🗓</div>
        <div class="kpi-val" style="color:#FF3B5C">${density}%</div>
        <div class="kpi-lbl">Calendar Density</div>
        <div class="kpi-trend" style="color:${parseFloat(density)>60?'#FF3B5C':parseFloat(density)>40?'#FFB800':'#00C48C'}">${parseFloat(density)>60?'🔴 Overloaded':parseFloat(density)>40?'⚠️ Heavy':'✅ Healthy'}</div>
      </div>
    </div>

    <!-- Top / Bottom meetings + Donut -->
    <div class="grid2">
      <div class="card">
        <div class="card-title">🏆 Top Performing Meetings</div>
        <table class="data-table">
          <thead><tr><th></th><th>Meeting</th><th>Score</th><th>Bar</th><th></th></tr></thead>
          <tbody>${topRows||'<tr><td colspan="5" style="text-align:center;color:#9898B8;padding:20px">No meetings found for this period</td></tr>'}</tbody>
        </table>
      </div>
      <div class="card">
        <div class="card-title">⚠️ Needs Improvement</div>
        <table class="data-table">
          <thead><tr><th></th><th>Meeting</th><th>Score</th><th></th><th>Reason</th></tr></thead>
