            <div class="legend-item"><div class="legend-dot" style="background:#00C48C"></div><div style="flex:1;color:#4A4A6A">Discussion</div><strong style="font-family:monospace;color:#00C48C">${discPct}%</strong></div>
            <div class="legend-item"><div class="legend-dot" style="background:#FFB800"></div><div style="flex:1;color:#4A4A6A">Idle / wasted</div><strong style="font-family:monospace;color:#FFB800">${idlePct}%</strong></div>
