      </div>
      ${meetingDetailCards||'<p style="color:#9898B8;font-size:13px;padding:16px">No meetings found for this period. Run an analysis first.</p>'}
    </div>

    <!-- Physical Meetings Summary -->
    \${physicalCount > 0 ? '<div class="card" style="margin-bottom:18px"><div class="card-title">\uD83C\uDFE2 Physical (In-Person) Meetings</div><table class="data-table"><thead><tr><th>Meeting</th><th>Date</th><th>Duration</th><th>Type</th><th>Attendees</th></tr></thead><tbody>' + physicalMeetings.map(pm => '<tr><td><strong>' + pm.summary + '</strong></td><td>' + new Date(pm.start).toLocaleDateString("en-US",{weekday:"short",month:"short",day:"numeric"}) + '</td><td>' + pm.duration + ' min</td><td>' + pm.type + '</td><td>' + pm.attendees + ' ppl</td></tr>').join('') + '</tbody></table><div style="padding:12px 16px;background:#F9FAFB;border-radius:0 0 10px 10px;font-size:12px;color:#9898B8;border-top:1px solid #E8EAEE">\u2139\uFE0F These meetings happened in person and have no Fathom transcript. They are excluded from scores and AI analysis.</div></div>' : ''}

    <div class="grid3">
