</main>

<script>
  // Inject webhook URL — replace with your n8n cloud webhook URL
  const WEBHOOK_URL = '__WEBHOOK_BASE_URL__/webhook/run-meeting-analysis';

  function runAnalysis() {
    const btn = document.getElementById('runBtn');
    const status = document.getElementById('statusMsg');
    const runStatus = document.getElementById('runStatus');
    btn.disabled = true;
    btn.textContent = '⏳ Starting...';

    const body = {
      dateFrom:   document.getElementById('dateFrom').value || null,
      dateTo:     document.getElementById('dateTo').value   || null,
      workHours:  document.getElementById('workHours').value ? parseFloat(document.getElementById('workHours').value) : 8,
      workDays:   document.getElementById('workDays').value  ? parseFloat(document.getElementById('workDays').value)  : 5,
      minDuration:parseFloat(document.getElementById('minDuration').value)||0,
      typeFilter: document.getElementById('typeFilter').value||null
    };

    fetch(WEBHOOK_URL, {
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body: JSON.stringify(body)
    })
    .then(r=>r.json())
    .then(data=>{
      status.innerHTML = '✅ ' + (data.message||'Analysis started!');
      runStatus.style.display='block';
      btn.textContent = '▶ Run Analysis';
      btn.disabled = false;
      // Auto-refresh after 90s
      setTimeout(()=>window.location.reload(), 90000);
    })
    .catch(()=>{
      status.innerHTML = '❌ Could not reach n8n. Check webhook URL.';
      btn.textContent = '▶ Run Analysis';
      btn.disabled = false;
    });
  }

  function skipForm() {
    fetch(WEBHOOK_URL, {
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body: JSON.stringify({useDefaults:true})
    }).catch(()=>{});
    document.getElementById('formPanel').style.display='none';
    document.getElementById('runStatus').style.display='block';
    setTimeout(()=>window.location.reload(), 90000);
  }

  function refreshDashboard(){
    const btn=document.getElementById('refreshBtn');
    btn.textContent='⏳ Loading...';
    btn.disabled=true;
    window.location.reload();
  }
</script>
</body>
</html>`;

return [{ json: { dashboardHtml: html, contentType: 'text/html' } }];

const meetings = $('Query Weekly Summary').all().map(i => i.json);
const participants = $('Query Participant Leaderboard').all().map(i => i.json);
let tw = {};
try { tw = $('Resolve Inputs & Defaults').first().json; } catch(e) { tw = { weekLabel: 'Latest Week' }; }

if (!participants.length) {
  return [{ json: { subject: '\U0001F4CB Self Evaluation - No Data', report: '<p>No participant data available.</p>' } }];
}

// Identify "self" = participant who attended the most meetings (calendar owner)
const self = participants.reduce((a, b) =>
  (parseInt(a.meetings_attended)||0) >= (parseInt(b.meetings_attended)||0) ? a : b
);

const name = self.participant_name;
const email = self.identity || name;
const avgScore = parseFloat(self.avg_score) || 0;
const totalSpeaking = parseFloat(self.total_speaking) || 0;
const totalDec = parseInt(self.total_decisions) || 0;
const totalDisc = parseInt(self.total_discussions) || 0;
const attended = parseInt(self.meetings_attended) || 0;
const role = (self.most_common_role || self.role || 'contributor').toLowerCase();
const rank = participants.findIndex(p => p.participant_name === name) + 1;
const totalP = participants.length;

const totalMeetMin = meetings.reduce((s,m) => s+(parseFloat(m.duration_minutes)||0), 0);
const speakRatio = totalMeetMin > 0 ? ((totalSpeaking / totalMeetMin) * 100).toFixed(1) : '0';
const personalDDR = (totalDec+totalDisc) > 0 ? ((totalDec/(totalDec+totalDisc))*100).toFixed(0) : '0';
const avgMeetScore = meetings.length > 0 ? (meetings.reduce((s,m)=>s+(parseFloat(m.meeting_score)||0),0)/meetings.length).toFixed(1) : '0';

// Strengths & Improvements
const strengths = [];
const improvements = [];

if (avgScore >= 75) strengths.push({icon:'\U0001F3AF',area:'High Impact Contributor',detail:'Score ' + avgScore + '/100 \u2014 you consistently drive value in meetings.'});
else if (avgScore >= 55) { strengths.push({icon:'\u2705',area:'Steady Contributor',detail:'Score ' + avgScore + '/100 shows reliable participation.'}); improvements.push({icon:'\U0001F4C8',area:'Increase Impact',detail:'Prepare 2-3 key talking points and propose action items to push above 75.'}); }
else improvements.push({icon:'\u26a0\ufe0f',area:'Meeting Engagement',detail:'Score ' + avgScore + '/100 is low. Prepare points before each meeting and actively participate.'});

const sr = parseFloat(speakRatio);
if (sr > 40) improvements.push({icon:'\U0001F399\ufe0f',area:'Communication Balance',detail:'You spoke ' + speakRatio + '% of total time. Create space for others \u2014 practice active listening.'});
else if (sr >= 15) strengths.push({icon:'\U0001F4AC',area:'Communication Balance',detail:speakRatio + '% speaking ratio \u2014 healthy balance of contributing and listening.'});
else if (sr < 8 && attended > 1) improvements.push({icon:'\U0001F4E2',area:'Speak Up More',detail:'Only ' + speakRatio + '% speaking time. Share insights, ask questions, propose ideas.'});

if (role === 'facilitator') strengths.push({icon:'\U0001F451',area:'Leadership',detail:'You frequently facilitate \u2014 strong organizational and initiative skills.'});
else if (role === 'observer') improvements.push({icon:'\U0001F440',area:'Active Participation',detail:'Mostly observer role. Try leading a section, taking notes, or asking clarifying questions.'});
else if (role === 'dominator') improvements.push({icon:'\u270b',area:'Collaboration',detail:'You tend to dominate. Practice asking open-ended questions and pausing for responses.'});

if (totalDec > totalDisc) strengths.push({icon:'\u26a1',area:'Decision-Oriented',detail:totalDec + ' decision vs ' + totalDisc + ' discussion contributions \u2014 you focus on outcomes.'});
else if (totalDec === 0 && attended > 2) improvements.push({icon:'\U0001F4A1',area:'Decision Making',detail:'Zero decision contributions across ' + attended + ' meetings. Propose solutions and make clear recommendations.'});

if (attended > 15) improvements.push({icon:'\U0001F4C5',area:'Meeting Overload',detail:attended + ' meetings is heavy. Decline non-essential ones or suggest async for low-score meetings.'});

// Next meeting prep by type
const typeMap = {};
for (const m of meetings) { const t=m.meeting_type||'general'; typeMap[t]=(typeMap[t]||0)+1; }
const prepGuide = {
  standup: {icon:'\U0001F504',tip:'Prepare a 30-second update: done, planned, blockers. Be concise.'},
  '1:1': {icon:'\U0001F464',tip:'Write 3 topics: career goals, feedback needed, project blockers.'},
  planning: {icon:'\U0001F5FA\ufe0f',tip:'Review backlog beforehand. Come with effort estimates for your tasks.'},
  review: {icon:'\U0001F50D',tip:'Test the feature/code before the meeting. Prepare specific constructive feedback.'},
  retrospective: {icon:'\U0001F504',tip:'Think of 1 win, 1 pain point, and 1 actionable improvement.'},
  'all-hands': {icon:'\U0001F4E2',tip:'Prepare 1 question for leadership. Note action items for your team.'},
  sync: {icon:'\U0001F517',tip:'Bring status updates and blockers. Keep it focused on cross-team dependencies.'},
  general: {icon:'\U0001F4CB',tip:'Review the agenda 5 min before. Prepare 2-3 talking points.'}
};

const sortedTypes = Object.entries(typeMap).sort((a,b)=>b[1]-a[1]);
const prepCards = sortedTypes.map(([type, count]) => {
  const g = prepGuide[type] || prepGuide.general;
  return '<div style="background:#F9FAFB;border:1px solid #E8EAEE;border-radius:10px;padding:16px;margin-bottom:10px">' +
    '<div style="display:flex;align-items:center;gap:8px;margin-bottom:8px"><span style="font-size:20px">' + g.icon + '</span><strong style="text-transform:capitalize">' + type + '</strong><span style="background:#FFF0E6;color:#FF6600;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:700">' + count + ' meetings</span></div>' +
    '<div style="font-size:13.5px;color:#4A4A6A;line-height:1.5">' + g.tip + '</div></div>';
}).join('');

// Skill radar values
const communication = Math.min(100, Math.round(sr * 2.5 + avgScore * 0.3));
const leadership = role === 'facilitator' ? 85 : role === 'contributor' ? 55 : role === 'observer' ? 25 : 40;
const decisionMaking = Math.min(100, parseInt(personalDDR) * 1.2 + (totalDec > 0 ? 20 : 0));
const collaboration = Math.min(100, avgScore * 0.6 + (sr > 10 && sr < 35 ? 30 : 10) + (totalDisc > 0 ? 15 : 0));
const efficiency = Math.min(100, parseFloat(avgMeetScore) * 0.8 + (attended < 12 ? 20 : 0));

function skillBar(label, val, color) {
  return '<div style="margin-bottom:14px"><div style="display:flex;justify-content:space-between;margin-bottom:5px"><span style="font-size:13px;font-weight:600;color:#1A1A2E">' + label + '</span><span style="font-size:13px;font-weight:800;font-family:monospace;color:' + color + '">' + val + '/100</span></div><div style="height:8px;background:#F0F0F5;border-radius:4px;overflow:hidden"><div style="height:100%;width:' + val + '%;background:' + color + ';border-radius:4px;transition:width .5s"></div></div></div>';
}

const overallGrade = Math.round((communication + leadership + decisionMaking + collaboration + efficiency) / 5);
const gradeColor = overallGrade >= 70 ? '#00C48C' : overallGrade >= 45 ? '#FFB800' : '#FF3B5C';
const gradeLabel = overallGrade >= 80 ? 'Excellent' : overallGrade >= 65 ? 'Good' : overallGrade >= 45 ? 'Average' : 'Needs Work';

// TOP IMPROVEMENT FOCUS
const topFocus = improvements.length > 0 ? improvements[0] : { icon:'\u2705', area:'Maintain Momentum', detail:'Great performance! Keep showing up prepared and engaged.' };

// Build HTML
let h = '<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="margin:0;padding:0;background:#f4f6f9;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,Helvetica,Arial,sans-serif">';
h += '<div style="max-width:680px;margin:20px auto;background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 2px 12px rgba(0,0,0,0.08)">';

// Header
h += '<div style="background:linear-gradient(135deg,#1E1E2E 50%,#FF6600);padding:28px 32px;color:#fff">';
h += '<h1 style="margin:0 0 4px 0;font-size:22px">\U0001F9D1\u200d\U0001F4BC Personal Meeting Self-Evaluation</h1>';
h += '<p style="margin:0;opacity:0.85;font-size:14px">\U0001F4C5 ' + (tw.weekLabel || 'Latest Week') + ' \u00b7 ' + name + ' (' + email + ')</p>';
h += '</div>';

// Overall grade card
h += '<div style="display:flex;align-items:center;gap:24px;padding:24px 32px;border-bottom:1px solid #eee">';
h += '<div style="width:80px;height:80px;border-radius:50%;background:' + gradeColor + '20;display:flex;align-items:center;justify-content:center;flex-shrink:0"><div style="text-align:center"><div style="font-size:28px;font-weight:900;color:' + gradeColor + '">' + overallGrade + '</div><div style="font-size:10px;color:' + gradeColor + ';font-weight:700;text-transform:uppercase">' + gradeLabel + '</div></div></div>';
h += '<div style="flex:1"><div style="font-size:16px;font-weight:700;color:#1A1A2E;margin-bottom:4px">Overall Meeting Performance</div>';
h += '<div style="font-size:13px;color:#888">Rank <strong style="color:#FF6600">#' + rank + '</strong> of ' + totalP + ' participants \u00b7 ' + attended + ' meetings attended \u00b7 ' + totalSpeaking.toFixed(0) + ' min speaking</div></div></div>';

// Quick stats
h += '<div style="display:flex;border-bottom:1px solid #eee">';
const qs = (icon,label,value,sub) => '<div style="flex:1;padding:16px 20px;text-align:center;border-right:1px solid #eee"><div style="font-size:18px">' + icon + '</div><div style="font-size:20px;font-weight:700;color:#1a1a2e">' + value + '</div><div style="font-size:11px;color:#888">' + label + '</div>' + (sub?'<div style="font-size:10px;color:#aaa;margin-top:2px">' + sub + '</div>':'') + '</div>';
h += qs('\U0001F4C5','Meetings',attended,'attended');
h += qs('\U0001F399\ufe0f','Speaking',totalSpeaking.toFixed(0)+'min',speakRatio+'% of time');
h += qs('\u26a1','Decisions',totalDec,personalDDR+'% ratio');
h += qs('\U0001F3AF','Avg Score',avgScore+'/100',role);
h += '</div>';

// Content area
h += '<div style="padding:24px 28px">';

// Skill breakdown
h += '<h2 style="font-size:16px;color:#1a1a2e;margin:0 0 16px 0">\U0001F4CA Skill Assessment</h2>';
h += skillBar('\U0001F4AC Communication', communication, '#3B82F6');
h += skillBar('\U0001F451 Leadership', leadership, '#FF6600');
h += skillBar('\u26a1 Decision Making', decisionMaking, '#00C48C');
h += skillBar('\U0001F91D Collaboration', collaboration, '#9333EA');
h += skillBar('\u23f1 Efficiency', efficiency, '#FFB800');

// Strengths
if (strengths.length > 0) {
  h += '<h2 style="font-size:16px;color:#00C48C;margin:24px 0 12px 0">\U0001F4AA Your Strengths</h2>';
  strengths.forEach(s => {
    h += '<div style="display:flex;gap:12px;padding:12px 16px;background:#E8FAF4;border-radius:10px;margin-bottom:8px;border-left:4px solid #00C48C">';
    h += '<div style="font-size:18px">' + s.icon + '</div>';
    h += '<div><strong style="font-size:13px;color:#1A1A2E">' + s.area + '</strong><div style="font-size:12.5px;color:#4A4A6A;margin-top:2px">' + s.detail + '</div></div></div>';
  });
}

// Improvements
if (improvements.length > 0) {
  h += '<h2 style="font-size:16px;color:#FF6600;margin:24px 0 12px 0">\U0001F527 Areas to Improve</h2>';
  improvements.forEach(imp => {
    h += '<div style="display:flex;gap:12px;padding:12px 16px;background:#FFF0E6;border-radius:10px;margin-bottom:8px;border-left:4px solid #FF6600">';
    h += '<div style="font-size:18px">' + imp.icon + '</div>';
    h += '<div><strong style="font-size:13px;color:#1A1A2E">' + imp.area + '</strong><div style="font-size:12.5px;color:#4A4A6A;margin-top:2px">' + imp.detail + '</div></div></div>';
  });
}

// Prep guide
h += '<h2 style="font-size:16px;color:#1a1a2e;margin:24px 0 12px 0">\U0001F4DD Next Meeting Prep Guide</h2>';
h += prepCards;

// Top focus box
h += '<div style="background:linear-gradient(135deg,#1E1E2E,#2D2D44);color:#fff;border-radius:12px;padding:20px 24px;margin-top:24px">';
h += '<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:rgba(255,255,255,.5);margin-bottom:8px">\U0001F3AF #1 Focus for Next Week</div>';
h += '<div style="font-size:15px;font-weight:600">' + topFocus.icon + ' ' + topFocus.area + '</div>';
h += '<div style="font-size:13px;opacity:.85;margin-top:6px;line-height:1.5">' + topFocus.detail + '</div></div>';

h += '</div>';

// Footer
h += '<div style="background:#f8f9fa;padding:16px 28px;text-align:center;font-size:12px;color:#aaa;border-top:1px solid #eee">';
h += 'Self-Evaluation by <strong style="color:#FF6600">Smart Meeting Efficiency Analyzer v5</strong> \u00b7 n8n + GPT-4.1 + Fathom AI';
h += '</div></div></body></html>';

const subject = '\U0001F9D1\u200d\U0001F4BC Self-Evaluation: ' + name + ' \u2014 Score ' + overallGrade + '/100 | ' + (tw.weekLabel || 'Latest Week');

return [{ json: { report: h, subject } }];
